import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class LocationSharingBanner extends StatelessWidget { final bool isSharing; final VoidCallback onToggle; const LocationSharingBanner({super.key, required this.isSharing, required this.onToggle}); @override Widget build(BuildContext context) => Container(padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 10), color: isSharing ? AppTheme.primaryColor.withOpacity(0.1) : AppTheme.darkSurface, child: Row(children: [Icon(isSharing ? Icons.location_on : Icons.location_off, color: isSharing ? AppTheme.primaryColor : AppTheme.darkSubtext, size: 18), const SizedBox(width: 8), Expanded(child: Text(isSharing ? 'Sharing your location' : 'Location sharing off', style: TextStyle(color: isSharing ? AppTheme.primaryColor : AppTheme.darkSubtext, fontSize: 13))), Switch(value: isSharing, onChanged: (_) => onToggle(), activeColor: AppTheme.primaryColor)])); }